.darma-loader-uiverse-gearbox-sync {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

@keyframes darma-loader-uiverse-gearbox-sync-clockwise {
0% {
transform: rotate(0deg);
}

100% {
transform: rotate(360deg);
}
}

@keyframes darma-loader-uiverse-gearbox-sync-counter-clockwise {
0% {
transform: rotate(0deg);
}

100% {
transform: rotate(-360deg);
}
}

.darma-loader-uiverse-gearbox-sync__gearbox {
background: #111;
height: 150px;
width: 200px;
position: relative;
border: none;
overflow: hidden;
border-radius: 6px;
box-shadow: 0px 0px 0px 1px rgba(255, 255, 255, 0.1);
}

.darma-loader-uiverse-gearbox-sync__gearbox .darma-loader-uiverse-gearbox-sync__overlay {
border-radius: 6px;
content: "";
position: absolute;
top: 0;
left: 0;
width: 100%;
height: 100%;
z-index: 10;
box-shadow: inset 0px 0px 20px black;
transition: background 0.2s;
}

.darma-loader-uiverse-gearbox-sync__gearbox .darma-loader-uiverse-gearbox-sync__overlay {
background: transparent;
}

.darma-loader-uiverse-gearbox-sync__gear {
position: absolute;
height: 60px;
width: 60px;
box-shadow: 0px -1px 0px 0px #888888, 0px 1px 0px 0px black;
border-radius: 30px;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__large {
height: 120px;
width: 120px;
border-radius: 60px;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__large:after {
height: 96px;
width: 96px;
border-radius: 48px;
margin-left: -48px;
margin-top: -48px;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__one {
top: 12px;
left: 10px;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__two {
top: 61px;
left: 60px;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__three {
top: 110px;
left: 10px;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__four {
top: 13px;
left: 128px;
}

.darma-loader-uiverse-gearbox-sync__gear:after {
content: "";
position: absolute;
height: 36px;
width: 36px;
border-radius: 36px;
background: #111;
top: 50%;
left: 50%;
margin-left: -18px;
margin-top: -18px;
z-index: 3;
box-shadow: 0px 0px 10px rgba(255, 255, 255, 0.1), inset 0px 0px 10px rgba(0, 0, 0, 0.1), inset 0px 2px 0px 0px #090909, inset 0px -1px 0px 0px #888888;
}

.darma-loader-uiverse-gearbox-sync__gear-inner {
position: relative;
height: 100%;
width: 100%;
background: #555;
border-radius: 30px;
border: 1px solid rgba(255, 255, 255, 0.1);
}

.darma-loader-uiverse-gearbox-sync__large .darma-loader-uiverse-gearbox-sync__gear-inner {
border-radius: 60px;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__one .darma-loader-uiverse-gearbox-sync__gear-inner {
animation: counter-darma-loader-uiverse-gearbox-sync-clockwise 3s infinite linear;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__two .darma-loader-uiverse-gearbox-sync__gear-inner {
animation: darma-loader-uiverse-gearbox-sync-clockwise 3s infinite linear;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__three .darma-loader-uiverse-gearbox-sync__gear-inner {
animation: counter-darma-loader-uiverse-gearbox-sync-clockwise 3s infinite linear;
}

.darma-loader-uiverse-gearbox-sync__gear.darma-loader-uiverse-gearbox-sync__four .darma-loader-uiverse-gearbox-sync__gear-inner {
animation: counter-darma-loader-uiverse-gearbox-sync-clockwise 6s infinite linear;
}

.darma-loader-uiverse-gearbox-sync__gear-inner .darma-loader-uiverse-gearbox-sync__bar {
background: #555;
height: 16px;
width: 76px;
position: absolute;
left: 50%;
margin-left: -38px;
top: 50%;
margin-top: -8px;
border-radius: 2px;
border-left: 1px solid rgba(255, 255, 255, 0.1);
border-right: 1px solid rgba(255, 255, 255, 0.1);
}

.darma-loader-uiverse-gearbox-sync__large .darma-loader-uiverse-gearbox-sync__gear-inner .darma-loader-uiverse-gearbox-sync__bar {
margin-left: -68px;
width: 136px;
}

.darma-loader-uiverse-gearbox-sync__gear-inner .darma-loader-uiverse-gearbox-sync__bar:nth-child(2) {
transform: rotate(60deg);
}

.darma-loader-uiverse-gearbox-sync__gear-inner .darma-loader-uiverse-gearbox-sync__bar:nth-child(3) {
transform: rotate(120deg);
}

.darma-loader-uiverse-gearbox-sync__gear-inner .darma-loader-uiverse-gearbox-sync__bar:nth-child(4) {
transform: rotate(90deg);
}

.darma-loader-uiverse-gearbox-sync__gear-inner .darma-loader-uiverse-gearbox-sync__bar:nth-child(5) {
transform: rotate(30deg);
}

.darma-loader-uiverse-gearbox-sync__gear-inner .darma-loader-uiverse-gearbox-sync__bar:nth-child(6) {
transform: rotate(150deg);
}

